const e=JSON.parse('{"key":"v-2a9b91a4","path":"/notes/Additional/design_pattern/%E6%A1%A5%E6%8E%A5%E6%A8%A1%E5%BC%8F.html","title":"桥接模式","lang":"zh-CN","frontmatter":{"description":"桥接模式 介绍 桥接模式是一种结构型设计模式，它旨在将抽象部分与其实现部分分离，使它们可以独立地变化。它通过创建一个桥接接口，将抽象和实现解耦，使它们可以独立地进行扩展。 在桥接模式中，存在两个维度的抽象和实现，通过桥接接口将它们连接起来。其中，抽象部分定义了高层的抽象方法和属性，而实现部分定义了具体实现的方法和属性。通过桥接接口，抽象部分和实现部分可以独立地进行扩展和变化，而彼此之间的关系通过桥接接口来实现。 结构 image-20230530152030299","head":[["meta",{"property":"og:url","content":"https://mister-hope.github.io/notes/Additional/design_pattern/%E6%A1%A5%E6%8E%A5%E6%A8%A1%E5%BC%8F.html"}],["meta",{"property":"og:title","content":"桥接模式"}],["meta",{"property":"og:description","content":"桥接模式 介绍 桥接模式是一种结构型设计模式，它旨在将抽象部分与其实现部分分离，使它们可以独立地变化。它通过创建一个桥接接口，将抽象和实现解耦，使它们可以独立地进行扩展。 在桥接模式中，存在两个维度的抽象和实现，通过桥接接口将它们连接起来。其中，抽象部分定义了高层的抽象方法和属性，而实现部分定义了具体实现的方法和属性。通过桥接接口，抽象部分和实现部分可以独立地进行扩展和变化，而彼此之间的关系通过桥接接口来实现。 结构 image-20230530152030299"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"og:updated_time","content":"2023-06-16T08:05:24.000Z"}],["meta",{"property":"article:author","content":"ameee"}],["meta",{"property":"article:modified_time","content":"2023-06-16T08:05:24.000Z"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"桥接模式\\",\\"image\\":[\\"\\"],\\"dateModified\\":\\"2023-06-16T08:05:24.000Z\\",\\"author\\":[{\\"@type\\":\\"Person\\",\\"name\\":\\"ameee\\",\\"url\\":\\"https://mrhope.site\\"}]}"]]},"headers":[{"level":2,"title":"介绍","slug":"介绍","link":"#介绍","children":[]},{"level":2,"title":"结构","slug":"结构","link":"#结构","children":[]},{"level":2,"title":"角色","slug":"角色","link":"#角色","children":[]},{"level":2,"title":"实现","slug":"实现","link":"#实现","children":[]}],"git":{"createdTime":1686902724000,"updatedTime":1686902724000,"contributors":[{"name":"oooo","email":"ameee9@163.com","commits":1}]},"readingTime":{"minutes":2.17,"words":651},"filePathRelative":"notes/Additional/design_pattern/桥接模式.md","localizedDate":"2023年6月16日","excerpt":"<h1> 桥接模式</h1>\\n<h2> 介绍</h2>\\n<p>桥接模式是一种结构型设计模式，它旨在将抽象部分与其实现部分分离，使它们可以独立地变化。它通过创建一个桥接接口，将抽象和实现解耦，使它们可以独立地进行扩展。</p>\\n<p>在桥接模式中，存在两个维度的抽象和实现，通过桥接接口将它们连接起来。其中，抽象部分定义了高层的抽象方法和属性，而实现部分定义了具体实现的方法和属性。通过桥接接口，抽象部分和实现部分可以独立地进行扩展和变化，而彼此之间的关系通过桥接接口来实现。</p>\\n<h2> 结构</h2>\\n<figure><img src=\\"https://oooooo.oss-cn-fuzhou.aliyuncs.com/img/image-20230530152030299.png\\" alt=\\"image-20230530152030299\\" tabindex=\\"0\\" loading=\\"lazy\\"><figcaption>image-20230530152030299</figcaption></figure>","autoDesc":true}');export{e as data};
